1	import { useEffect, useState, useRef } from 'react'
2	import { createPortal } from 'react-dom'
3	import './CardModal.css'
4	import CommentList from '../CardModal/CommentList.jsx'
5	import BlockEditor from '../CardModal/BlockEditor.jsx'
6	
7	export default function CardModal({ card, onClose, onUpdate, onDelete, onAddComment = () => Promise.resolve() }) {
8	  // Edit state
9	  const [isEditingTitle, setIsEditingTitle] = useState(false)
10	  const [editTitle, setEditTitle]           = useState(card.title)
11	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
12	  const [editAssignee, setEditAssignee]     = useState(card.assignee ?? '')
13	  const [isEditingDescription, setIsEditingDescription] = useState(false)
14	  const [isSaving, setIsSaving]             = useState(false)
15	  const [saveError, setSaveError]           = useState(null)
16	
17	  // Delete state
18	  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
19	  const [isDeleting, setIsDeleting]               = useState(false)
20	
21	  // Focus refs
22	  const titleInputRef    = useRef(null)
23	  const assigneeInputRef = useRef(null)
24	
25	  // Focus effects
26	  useEffect(() => {
27	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
28	  }, [isEditingTitle])
29	
30	  useEffect(() => {
31	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
32	  }, [isEditingAssignee])
33	
34	  // Escape key handler — replaces the original handler
35	  useEffect(() => {
36	    function onKey(e) {
37	      if (e.key !== 'Escape') return
38	      if (isEditingTitle) {
39	        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
40	      } else if (isEditingAssignee) {
41	        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
42	      } else if (isEditingDescription) {
43	        // BlockEditor owns its own Escape handler; CardModal just prevents modal close
44	      } else {
45	        onClose()
46	      }
47	    }
48	    document.addEventListener('keydown', onKey)
49	    return () => document.removeEventListener('keydown', onKey)
50	  }, [onClose, isEditingTitle, isEditingAssignee, isEditingDescription, card.title, card.assignee])
51	
52	  // Save handlers
53	  async function handleSaveTitle() {
54	    if (editTitle.trim() === '') {
55	      setSaveError('Title is required')
56	      return
57	    }
58	    setIsSaving(true); setSaveError(null)
59	    try {
60	      await onUpdate(card.id, { title: editTitle })
61	      setIsEditingTitle(false)
62	    } catch (err) {
63	      setSaveError(err.message)
64	    } finally {
65	      setIsSaving(false)
66	    }
67	  }
68	
69	  async function handleSaveAssignee() {
70	    setIsSaving(true); setSaveError(null)
71	    try {
72	      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
73	      setIsEditingAssignee(false)
74	    } catch (err) {
75	      setSaveError(err.message)
76	    } finally {
77	      setIsSaving(false)
78	    }
79	  }
80	
81	  async function handleConfirmDelete() {
82	    setIsDeleting(true); setSaveError(null)
83	    try {
84	      await onDelete(card.id)
85	      onClose()
86	    } catch (err) {
87	      setSaveError(err.message)
88	      setShowDeleteConfirm(false)
89	    } finally {
90	      setIsDeleting(false)
91	    }
92	  }
93	
94	  return createPortal(
95	    <div className="modal-overlay" onClick={onClose}>
96	      <div
97	        className="modal-content"
98	        role="dialog"
99	        aria-modal="true"
100	        aria-label={card.title}
101	        onClick={e => e.stopPropagation()}
102	      >
103	        {/* 1. Close button */}
104	        <button className="modal-close" onClick={onClose} aria-label="Close">
105	          ✕
106	        </button>
107	
108	        {/* 2. Title field (editable) */}
109	        {isEditingTitle ? (
110	          <div className="modal-field-edit">
111	            <input
112	              ref={titleInputRef}
113	              aria-label="Title"
114	              value={editTitle}
115	              onChange={e => setEditTitle(e.target.value)}
116	              onKeyDown={e => { if (e.key === 'Enter') handleSaveTitle() }}
117	            />
118	            <button aria-label="Save" onClick={handleSaveTitle} disabled={isSaving}>
119	              {isSaving ? 'Saving…' : 'Save'}
120	            </button>
121	            <button
122	              aria-label="Cancel"
123	              disabled={isSaving}
124	              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
125	            >
126	              Cancel
127	            </button>
128	          </div>
129	        ) : (
130	          <div className="modal-field-view">
131	            <h2 className="modal-title">{card.title}</h2>
132	            <button
133	              aria-label="Edit title"
134	              onClick={() => {
135	                setIsEditingTitle(true); setEditTitle(card.title)
136	                // Mutual exclusivity: close assignee edit if open
137	                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
138	              }}
139	            >
140	              Edit
141	            </button>
142	          </div>
143	        )}
144	
145	        {/* 3. Assignee field (editable) */}
146	        {isEditingAssignee ? (
147	          <div className="modal-field-edit">
148	            <input
149	              ref={assigneeInputRef}
150	              aria-label="Assignee"
151	              value={editAssignee}
152	              onChange={e => setEditAssignee(e.target.value)}
153	              onKeyDown={e => { if (e.key === 'Enter') handleSaveAssignee() }}
154	            />
155	            <button aria-label="Save" onClick={handleSaveAssignee} disabled={isSaving}>
156	              {isSaving ? 'Saving…' : 'Save'}
157	            </button>
158	            <button
159	              aria-label="Cancel"
160	              disabled={isSaving}
161	              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
162	            >
163	              Cancel
164	            </button>
165	          </div>
166	        ) : (
167	          <div className="modal-field-view">
168	            <p className="modal-assignee">
169	              <strong>Assignee:</strong> {card.assignee ?? 'Unassigned'}
170	            </p>
171	            <button
172	              aria-label="Edit assignee"
173	              onClick={() => {
174	                setIsEditingAssignee(true); setEditAssignee(card.assignee ?? '')
175	                // Mutual exclusivity: close title edit if open
176	                setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
177	              }}
178	            >
179	              Edit
180	            </button>
181	          </div>
182	        )}
183	
184	        {/* 4. Description (BlockNote editor) */}
185	        <BlockEditor
186	          content={card.description}
187	          onSave={(json) => onUpdate(card.id, { description: json })}
188	          onEditingChange={setIsEditingDescription}
189	        />
190	
191	        {/* 5. Error alert */}
192	        {saveError && <p role="alert" className="modal-error">{saveError}</p>}
193	
194	        {/* 6. Comments section */}
195	        <CommentList
196	          comments={card.comments}
197	          onAddComment={(data) => onAddComment(card.id, data)}
198	        />
199	
200	        {/* 7. Delete button / confirmation */}
201	        {showDeleteConfirm ? (
202	          <div className="modal-delete-confirm" role="region" aria-label="Delete confirmation">
203	            <p>Are you sure you want to delete this card?</p>
204	            <button
205	              aria-label="Confirm delete"
206	              onClick={handleConfirmDelete}
207	              disabled={isDeleting}
208	            >
209	              {isDeleting ? 'Deleting…' : 'Confirm delete'}
210	            </button>
211	            <button
212	              aria-label="Keep card"
213	              onClick={() => setShowDeleteConfirm(false)}
214	              disabled={isDeleting}
215	            >
216	              Keep card
217	            </button>
218	          </div>
219	        ) : (
220	          <button
221	            className="modal-delete"
222	            aria-label="Delete"
223	            onClick={() => setShowDeleteConfirm(true)}
224	          >
225	            Delete
226	          </button>
227	        )}
228	      </div>
229	    </div>,
230	    document.body
231	  )
232	}
